function extractAllMonthDayYearDates(text) {
  const monthNames = [
    "January","February","March","April","May","June",
    "July","August","September","October","November","December"
  ].join("|");

  // \b = word boundary → avoids matching inside other words
  const regex = new RegExp(`\\b(${monthNames})\\s+(\\d{1,2}),\\s+(\\d{4})\\b`, "gi");

  const dates = [];
  let match;

  while ((match = regex.exec(text)) !== null) {
    dates.push({
      full: match[0],     // "March 10, 2026"
      month: match[1],
      day:   match[2],
      year:  match[3]
    });
  }

  return dates;
}
let nextPay = extractAllMonthDayYearDates("{{nextPay}}");

nextPay = Date.parse(nextPay[0].full);
nextPay = new Date(nextPay);

const now = new Date();
const formatter = new Intl.DateTimeFormat('en-US', {
    timeZone: 'Europe/Berlin',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
    hour12: true, // Use false for 24-hour format
});

const date = new Date(formatter.format(now));

return date.getDate() === nextPay.getDate() &&
       (date.getMonth() + 1) === nextPay.getMonth() &&
       date.getFullYear() === nextPay.getFullYear();
